const storageLayer = {
  get: async (key) => {
    try { if (window.storage?.get) { const r = await window.storage.get(key); if (r?.value) return r.value; } } catch(e) {}
    try { const v = localStorage.getItem(key); if (v) return v; } catch(e) {}
    return null;
  },
  set: async (key, value) => {
    try { if (window.storage?.set) await window.storage.set(key, value); } catch(e) {}
    try { localStorage.setItem(key, value); } catch(e) {}
  },
  del: async (key) => {
    try { if (window.storage?.delete) await window.storage.delete(key); } catch(e) {}
    try { localStorage.removeItem(key); } catch(e) {}
  }
};

const LESSONS = [
  {title:"The AI Risk Management Framework",source:"NIST · AI RMF 1.0",insight:"NIST\'s AI RMF provides a voluntary framework for organizations to manage AI risks across four functions: Govern, Map, Measure, and Manage. It is the most widely adopted AI governance reference in the US and is already being cited in federal procurement requirements.",why:"Firms that cannot demonstrate AI risk governance will face client scrutiny, regulatory pressure, and liability exposure as AI adoption accelerates.",action:"Ask your IT or operations lead: do we have any AI tools in use, and do we have a governance process for evaluating their risk?",cat:"ai",pillar:"AI & Automation"},
  {title:"Foundation Models and Legal Risk",source:"ABA · Formal Opinion 512",insight:"The ABA\'s 2024 guidance on generative AI establishes that lawyers using AI tools must understand their capabilities and limitations, supervise AI output as they would associate work, and maintain confidentiality obligations when inputting client data.",why:"Every attorney using ChatGPT, Harvey, or any AI tool for client work is already subject to these obligations whether or not the firm has a policy.",action:"Identify which AI tools your attorneys are currently using personally and assess whether client data is being entered into any of them.",cat:"ai",pillar:"AI & Automation"},
  {title:"Responsible AI Governance in Practice",source:"OECD · AI Principles",insight:"The OECD AI Principles — adopted by 46 countries including the US — establish five values-based principles for trustworthy AI: inclusive growth, human-centered values, transparency, robustness, and accountability. These principles underpin most national AI regulatory frameworks.",why:"Understanding the OECD framework helps executives evaluate AI vendors and policies against a globally accepted baseline rather than marketing claims.",action:"When your next AI vendor pitches a product, ask them: how does your system address transparency and accountability under the OECD AI Principles?",cat:"ai",pillar:"AI & Automation"},
  {title:"The State of AI Adoption in Law",source:"8am.io · 2026 Legal Industry Report",insight:"70% of lawyers now use AI tools personally, yet 43% of firms have no AI policy. Only 19% of firms consider themselves prepared for AI\'s impact. The gap between individual AI use and organizational governance is the defining risk profile for law firms right now.",why:"Your attorneys are making AI decisions daily without firm guidance — creating liability exposure you may not be aware of.",action:"Survey your attorneys this week: which AI tools do you use, and for what tasks? The answers will likely surprise you.",cat:"ai",pillar:"AI & Automation"},
  {title:"AI and the Unauthorized Practice of Law",source:"State Bar Associations · 2024-2025 Ethics Opinions",insight:"Multiple state bars have issued AI ethics opinions concluding that AI output used in client matters must be reviewed by a licensed attorney, that AI cannot substitute for legal judgment, and that supervision duties extend to AI tools. Several bars have opened investigations into AI-related UPL incidents.",why:"Firms that deploy AI without supervision protocols are creating UPL exposure for individual attorneys and potential malpractice liability for the firm.",action:"Check whether your state bar has issued an AI ethics opinion. If yes, confirm your usage practices comply. If no, apply the ABA Formal Opinion 512 standard in the interim.",cat:"ai",pillar:"AI & Automation"},
  {title:"AI Hallucination as a Legal Risk",source:"Federal Courts · Mata v. Avianca (2023) and subsequent cases",insight:"Multiple federal courts have sanctioned attorneys for submitting AI-generated briefs containing fabricated case citations. Courts have made clear that reliance on AI output without independent verification violates Rule 11 and professional responsibility standards.",why:"A single hallucination incident can result in sanctions, client harm, malpractice exposure, and reputational damage that far exceeds the time saved using the tool.",action:"Establish a firm rule: every case citation generated by AI must be independently verified in Westlaw or Lexis before filing. No exceptions.",cat:"ai",pillar:"AI & Automation"},
  {title:"The TRUMP AMERICA AI Act and Federal Preemption",source:"US Congress · TRUMP AMERICA AI Act (2026 Draft)",insight:"The proposed TRUMP AMERICA AI Act would establish federal AI standards that preempt state AI laws — potentially nullifying Texas\'s TRAIGA and similar state-level frameworks. Federal preemption of AI regulation is actively debated and the outcome will determine which compliance framework governs your firm.",why:"Investing heavily in state-specific AI compliance (TRAIGA) before the federal preemption question is resolved may create redundant or contradicted obligations.",action:"Monitor the TRUMP AMERICA AI Act\'s progress and ask legal counsel to flag any conflict between your current TRAIGA compliance posture and the federal draft.",cat:"ai",pillar:"AI & Automation"},
  {title:"TRAIGA: What Texas Firms Must Know",source:"Texas Legislature · TX Responsible AI Governance Act",insight:"TRAIGA, effective January 1, 2026, imposes obligations on developers and deployers of high-risk AI systems in Texas — including requirements for impact assessments, transparency disclosures, and bias testing. Law firms using AI for client-facing decisions may qualify as deployers.",why:"Non-compliance exposes firms to civil enforcement, and the cure period provisions require documented governance processes that most firms don\'t currently have.",action:"Determine whether any AI tool your firm uses qualifies as a high-risk AI system under TRAIGA\'s definitions. If uncertain, engage outside counsel to assess.",cat:"ai",pillar:"AI & Automation"},
  {title:"AI Vendor Evaluation for Legal Professionals",source:"Wolters Kluwer · Future Ready Lawyer 2026",insight:"92% of lawyers use at least one AI tool daily, yet most firms have no formal vendor evaluation criteria. Key risk factors in AI vendor selection include data handling and confidentiality, model training on client data, output accuracy rates, and contractual liability allocation.",why:"The vendor you choose today will have access to your client data and your attorneys\' work product. Vendor selection is a risk management decision, not a technology decision.",action:"Request your primary AI vendor\'s data processing agreement and confirm your client data is not used for model training.",cat:"ai",pillar:"AI & Automation"},
  {title:"The Workforce Impact of Legal AI",source:"McKinsey Global Institute · The Economic Potential of Generative AI",insight:"McKinsey estimates that 44% of legal work activities are automatable with current AI — disproportionately affecting document review, contract analysis, research, and drafting. Firms that restructure around AI-augmented workflows will gain significant cost and speed advantages.",why:"The question is not whether AI will change your staffing model — it is whether you control that change or react to it after clients demand lower fees.",action:"Identify one practice area where AI could absorb routine work. Map what your attorneys could do with that recovered time if the transition were managed well.",cat:"ai",pillar:"AI & Automation"},
  {title:"Smart Contracts and Legal Enforceability",source:"Sideman & Bancroft · Smart Contracts Revisited: Lessons from the Courts (2025)",insight:"Recent case law — including Van Loon v. US Department of the Treasury (5th Circuit, 2024) — has begun to address whether smart contracts constitute enforceable legal agreements and whether immutable code can be sanctioned as property. The legal framework is unsettled but developing rapidly.",why:"Clients in real estate, finance, and supply chain are already using smart contracts. Advising them requires understanding the current enforceability landscape.",action:"Review one recent smart contract case in your jurisdiction. Begin tracking this area if any current clients operate in industries where smart contracts are emerging.",cat:"blockchain",pillar:"Blockchain & Digital Trust"},
  {title:"Digital Identity and Client Verification",source:"NIST · Digital Identity Guidelines SP 800-63",insight:"NIST\'s SP 800-63 defines assurance levels for digital identity verification — critical guidance for firms implementing KYC processes, client portal access, or remote onboarding. Identity assurance level determines what verification methods are legally defensible.",why:"Remote client relationships require defensible identity verification. Inadequate KYC processes expose firms to regulatory sanctions and create liability in the event of impersonation fraud.",action:"Assess your current client onboarding process: at what assurance level does your identity verification operate? Is it documented and defensible?",cat:"blockchain",pillar:"Blockchain & Digital Trust"},
  {title:"Blockchain in Legal Practice: Current Reality",source:"ABA · 2025 Legal Technology Survey",insight:"14% of law firms report direct client matters involving blockchain or digital assets. Transactional practices — real estate, M&A, finance — are most exposed. The primary practical areas are token offerings, DAO governance disputes, NFT IP questions, and digital asset estate planning.",why:"Your clients may have blockchain exposure you\'re not currently advising on because the technology outpaced the conversation.",action:"In your next client relationship review, add one question: do you or your business hold, transact, or have contractual obligations involving digital assets?",cat:"blockchain",pillar:"Blockchain & Digital Trust"},
  {title:"DAO Liability and Member Exposure",source:"Samuels v. Lido DAO · US District Court (2024)",insight:"The Samuels v. Lido DAO ruling held that DAO members may have unlimited personal liability as general partners if the DAO lacks a formal legal wrapper. This creates significant risk for clients who are DAO participants or token holders in governance structures.",why:"Clients who casually participate in DeFi governance without understanding their legal exposure may be accumulating personal liability without knowing it.",action:"If any clients are involved in DAO governance or DeFi protocols, flag this case for a conversation about their liability structure.",cat:"blockchain",pillar:"Blockchain & Digital Trust"},
  {title:"Tokenization of Real-World Assets",source:"World Economic Forum · Digital Assets Regulation Report 2025",insight:"Real-world asset tokenization — converting property, securities, and receivables into blockchain tokens — is projected to represent $16 trillion in assets by 2030. Regulatory frameworks are emerging but fragmented across jurisdictions, creating compliance complexity for early movers.",why:"Commercial real estate and private equity clients are increasingly exploring tokenization as a liquidity mechanism. Understanding the regulatory landscape is a prerequisite to advising them.",action:"Research your state\'s current position on tokenized securities and real estate. Identify one regulatory gap that could affect a current client.",cat:"blockchain",pillar:"Blockchain & Digital Trust"},
  {title:"The NIST Cybersecurity Framework 2.0",source:"NIST · Cybersecurity Framework 2.0 (2024)",insight:"NIST CSF 2.0 expanded the original five functions (Identify, Protect, Detect, Respond, Recover) with a sixth: Govern. The Govern function explicitly elevates cybersecurity to an enterprise risk management and board-level responsibility — not just an IT function.",why:"Clients and regulators increasingly expect firms to demonstrate governance-level cybersecurity oversight, not just technical controls. CSF 2.0 is the reference framework for that expectation.",action:"Ask your IT lead: are our cybersecurity practices mapped to NIST CSF 2.0? If not, identify the biggest gap between where you are and where the framework expects you to be.",cat:"cybersecurity",pillar:"Cybersecurity"},
  {title:"Attorney Data Breach Obligations",source:"ABA · Formal Opinion 483",insight:"ABA Opinion 483 establishes that attorneys have ethical duties to stop a breach, assess its scope, notify affected clients, and prevent recurrence — applying Rules 1.1, 1.4, 1.6, 5.1, and 5.3. These obligations arise from the breach itself, not from whether you caused it.",why:"A vendor breach affecting your client data triggers your ethical obligations even if you did nothing wrong. The firms that respond poorly do so because they had no plan.",action:"Confirm your firm has a documented data breach response plan. If not, assign ownership and a deadline to create one.",cat:"cybersecurity",pillar:"Cybersecurity"},
  {title:"Zero Trust Architecture",source:"CISA · Zero Trust Maturity Model 2.0",insight:"Zero Trust replaces the assumption that everything inside a network perimeter is safe. Instead, every user, device, and application must continuously verify identity before accessing resources. CISA\'s Maturity Model provides a five-pillar roadmap: Identity, Devices, Networks, Applications, and Data.",why:"Law firms are high-value targets precisely because of the sensitive client data they hold. Perimeter-based security alone is no longer adequate and is explicitly insufficient under current cyber insurance underwriting standards.",action:"Ask your IT team: do we operate on a zero-trust model or a perimeter model? If perimeter, what would it take to begin the migration?",cat:"cybersecurity",pillar:"Cybersecurity"},
  {title:"Legal Tech Supply Chain Risk",source:"LexisNexis · Data Breach Incident Report (March 2026)",insight:"A March 2026 breach of LexisNexis Legal & Professional exposed 400,000 user profiles including federal judges and law firm users. It was the second RELX breach in two years. Legal technology platforms are concentrated attack surfaces — a single vendor compromise can expose hundreds of firms.",why:"Your firm\'s cybersecurity posture is only as strong as your weakest vendor. Every legal tech platform you use is a potential entry point.",action:"List your top five legal technology vendors. For each, confirm: do they have a current SOC 2 report? Have they experienced a breach in the past three years?",cat:"cybersecurity",pillar:"Cybersecurity"},
  {title:"Cyber Insurance and the New Underwriting Reality",source:"Marsh · Cyber Insurance Market Report 2025",insight:"Cyber insurers now routinely require MFA on all remote access, endpoint detection and response tools, privileged access management, and documented incident response plans as conditions of coverage. Firms that cannot demonstrate these controls face premium increases or denial of coverage.",why:"A cyberattack without adequate insurance coverage could be a firm-ending event. The coverage you think you have may not pay out if basic controls are absent.",action:"Pull your current cyber insurance policy and the underwriting questionnaire you completed. Verify your answers are still accurate — misrepresentation voids coverage.",cat:"cybersecurity",pillar:"Cybersecurity"},
  {title:"Data Governance Fundamentals",source:"DAMA International · Data Management Body of Knowledge",insight:"Data governance is the system of decision rights and accountabilities for data-related processes. Effective governance defines who can take what actions with what data, under what circumstances, using what methods. Without it, data quality, privacy compliance, and AI readiness are impossible.",why:"Firms generating AI-assisted work product, handling client data across cloud platforms, and operating under data privacy regulations need data governance — not as an IT project, but as a firm-wide operating standard.",action:"Identify who in your firm is accountable for data quality and access decisions. If the answer is unclear, that is the governance gap.",cat:"data",pillar:"Data & Analytics"},
  {title:"Privacy by Design in Legal Operations",source:"International Association of Privacy Professionals · IAPP",insight:"Privacy by Design embeds data protection into systems and workflows from the outset rather than retrofitting compliance after the fact. It is required by GDPR Article 25 and referenced in TRAIGA. The seven foundational principles apply directly to client intake, matter management, and document storage.",why:"Retrofitting privacy compliance into existing systems is expensive and incomplete. Firms building new workflows now have a narrow window to do it right.",action:"Identify one new workflow or technology your firm is implementing. Before deployment, ask: what personal data does this touch, and how is it protected by design?",cat:"data",pillar:"Data & Analytics"},
  {title:"The Data-Driven Law Firm",source:"McKinsey & Company · Data and AI in Professional Services 2025",insight:"Leading law firms are deploying matter analytics to optimize staffing, pricing models informed by historical outcome data, and client relationship intelligence systems. Firms in the top quartile of data maturity report 20-30% higher profit margins than industry average.",why:"Data is already a competitive differentiator in legal services. Firms that treat data as an operational asset will outperform those that treat it as a byproduct.",action:"Identify one business decision your firm makes regularly that could be improved with better data. What data would you need, and do you currently capture it?",cat:"data",pillar:"Data & Analytics"},
  {title:"Client Data Ethics and Confidentiality",source:"ABA · Model Rules 1.6 and 1.9",insight:"Model Rule 1.6 requires reasonable measures to prevent unauthorized disclosure of client information. Rule 1.9 extends confidentiality obligations to former clients. Both rules apply to data stored in cloud platforms, shared with AI vendors, and accessed by remote employees.",why:"Client confidentiality is the bedrock obligation of legal practice. Modern data environments create new vectors for inadvertent disclosure that the rules fully cover.",action:"Audit where client data currently resides: local servers, cloud platforms, AI tools, and personal devices. Confirm each location meets your Rule 1.6 obligations.",cat:"data",pillar:"Data & Analytics"},
  {title:"Analytics Maturity in Professional Services",source:"Davenport & Bean · 2025 AI and Data Leadership Benchmark",insight:"Only 26% of professional services firms report having a data-driven culture despite 84% having appointed a Chief Data Officer. The gap between data leadership investment and actual analytics maturity is the defining challenge of enterprise data programs.",why:"Appointing a CDO or buying analytics tools does not produce data maturity. Culture, process, and decision-making integration determine whether the investment produces value.",action:"Ask your data or IT lead: name one business decision in the past quarter that was changed because of data analysis. If they struggle to answer, that is your baseline.",cat:"data",pillar:"Data & Analytics"},
  {title:"The Board\'s Cybersecurity Responsibility",source:"SEC · Cybersecurity Disclosure Rules (2023)",insight:"The SEC\'s 2023 cybersecurity rules require public companies to disclose material cybersecurity incidents within four days and to annually disclose board-level cybersecurity oversight processes. The rules signal that cybersecurity governance is now a board-level accountability, not just a management function.",why:"Your publicly traded clients are now required to demonstrate board-level cyber governance. Understanding these rules positions you to advise on compliance and on the governance questions their boards will ask.",action:"Review one client\'s recent 10-K cybersecurity disclosure. Assess whether their governance description is substantive or boilerplate — and whether your firm\'s posture could survive the same scrutiny.",cat:"governance",pillar:"Governance & Risk"},
  {title:"AI Governance at the Board Level",source:"Deloitte · Board Practices Report: AI Oversight 2025",insight:"Only 39% of boards have a formal AI oversight process despite 78% identifying AI as a top strategic risk. Deloitte identifies five board-level AI governance responsibilities: risk oversight, ethics and values alignment, regulatory compliance monitoring, talent and capability assessment, and strategic value realization.",why:"Your clients\' boards will increasingly be asked about AI governance by shareholders, regulators, and insurers. Advising on governance readiness is an emerging service opportunity.",action:"Identify two clients with active AI programs. In your next interaction, ask whether their board has discussed AI governance. Their answer reveals both a risk and an advisory opportunity.",cat:"governance",pillar:"Governance & Risk"},
  {title:"Technology as Competitive Advantage",source:"Harvard Business Review · Digital Transformation in Professional Services",insight:"Professional services firms that treat technology investment as overhead rather than competitive capability consistently underperform peers on growth, margin, and client retention. The differentiator is not the technology itself — it is the leadership capacity to select, deploy, and extract value from it.",why:"Technology fluency at the leadership level is what separates firms that successfully deploy AI from firms that buy tools and get friction.",action:"Identify one technology investment your firm made in the past two years. Assess honestly: did leadership understand it well enough to deploy it effectively?",cat:"techleadership",pillar:"Technology Leadership"},
  {title:"Leading Through Digital Transformation",source:"MIT Sloan Management Review · Digital Leadership Capabilities 2025",insight:"MIT Sloan research identifies three capabilities that distinguish effective digital leaders: the ability to translate between business strategy and technology capability, a tolerance for iterative experimentation, and the habit of continuous technology learning. The third is the rarest and most impactful.",why:"Executives who stop learning about technology become dependent on advisors who may not share their strategic interests. Continuous learning is a leadership discipline, not a hobby.",action:"Identify one technology topic relevant to your firm that you don\'t fully understand. Commit to one hour of structured learning on it this week.",cat:"techleadership",pillar:"Technology Leadership"},
  {title:"The Conscious Competence of Technology",source:"Gordon Training International · Conscious Competence Model",insight:"Leaders move through four stages in any new domain: unconscious incompetence (don\'t know what you don\'t know), conscious incompetence (aware of the gap), conscious competence (capable with effort), unconscious competence (fluent). Most executives are at stage one or two on AI. Recognizing that honestly is the prerequisite to progress.",why:"The executives most at risk are those who believe they understand AI because they use ChatGPT occasionally. Awareness of the gap is the beginning of genuine competence.",action:"Pick one technology pillar — AI, cybersecurity, blockchain, or data. Honestly assess which stage you\'re at. That assessment is your development starting point.",cat:"techleadership",pillar:"Technology Leadership"},
  {title:"Technology Investment ROI for Law Firms",source:"Thomson Reuters · Law Firm Financial Performance Report 2025",insight:"Law firms investing more than 3.5% of revenue in technology report 23% higher revenue per attorney and 18% higher client retention than firms below that threshold. The ROI correlation is strongest in firms where managing partners are personally involved in technology strategy.",why:"Technology investment without leadership engagement produces tools that get adopted partially and abandoned early. The managing partner\'s attention is the multiplier on the investment.",action:"Identify your firm\'s technology spend as a percentage of revenue. Compare it to the 3.5% threshold and assess whether the gap represents risk or opportunity.",cat:"techleadership",pillar:"Technology Leadership"},
];

